INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-6f0ba476-moex-00221', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-113-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '在兩期生命循環週期模型中，甲、乙兩人僅在第一期有勞動所得10,000元， 利率為10%。甲在第一期消費所有的稅後所得，乙則全部存入銀行以供第二 期消費。比較兩期稅率皆為50%的消費稅與所得稅所產生的租稅負擔，下列 敘述何者正確？', '["若課徵所得稅，甲的終身所得稅稅負較乙為多", "若課徵消費稅，甲的終身消費稅稅負較乙為多", "若課徵所得稅，則甲與乙負擔相同的終身所得稅稅負", "若課徵消費稅，則甲與乙負擔相同的終身消費稅稅負"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:28+00:00", "source_pdf_sha1": "340fd4aa51e1", "answer_pdf_sha1": "2b16893eca27", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "305", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00222', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-113-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '依我國加值型及非加值型營業稅法規定，有關外國公司在我國境內銷售勞務 行為之納稅義務人，下列敘述何者錯誤？', '["在中華民國境內設有固定營業場所者，銷售電子勞務與我國境內自然人， 應由該外國公司申報繳納營業稅", "在中華民國境內設有固定營業場所者，銷售非電子勞務與我國境內自然 人，應由勞務買受人申報繳納營業稅", "在中華民國境內無固定營業場所者，銷售電子勞務與我國境內自然人，應 由該外國公司申報繳納營業稅", "在中華民國境內無固定營業場所者，銷售非電子勞務與我國境內自然人， 應由勞務買受人申報繳納營業稅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:28+00:00", "source_pdf_sha1": "340fd4aa51e1", "answer_pdf_sha1": "2b16893eca27", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "305", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00223', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-113-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '各地方政府為提高房屋持有成本，抑制房產炒作，得將下列何種房屋依所有 權人持屋戶數訂定差別稅率？', '["供公益出租人出租使用的房屋", "供住家使用的房屋", "供自由職業事務所使用的房屋", "供營業使用的房屋"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:28+00:00", "source_pdf_sha1": "340fd4aa51e1", "answer_pdf_sha1": "2b16893eca27", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "305", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00224', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-113-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '有關遺產稅課稅主體與客體之規定，下列何者正確？', '["於我國登記之專利權，應視為境內財產", "遺產中之上市股票，以繼承開始日之平均成交價為估價標準", "繼承人在繼承發生前2年內，在境內有住所者，則其境內外之全部遺產， 均應於我國課徵遺產稅", "在境外死亡之我國國民，無須於我國課徵遺產稅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:28+00:00", "source_pdf_sha1": "340fd4aa51e1", "answer_pdf_sha1": "2b16893eca27", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "305", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00225', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-113-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '依現行土地稅法規定，土地所有權移轉或設定典權時，移轉現值的審核標準 之敘述，下列何者錯誤？', '["依法院判決移轉登記者，以申報人向法院起訴日當期之公告土地現值為準", "申報人於訂定契約之日起 30 日內申報者，以訂約日當期之公告土地現值 為準", "申報人逾訂定契約之日起 30 日始申報者，以訂約日當期之公告土地現值 為準", "遺贈之土地，以遺贈人死亡日當期之公告土地現值為準"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:28+00:00", "source_pdf_sha1": "340fd4aa51e1", "answer_pdf_sha1": "2b16893eca27", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "305", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00226', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-113-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '關於印花稅課稅之敘述，下列何者錯誤？', '["公私立學校處理公款所發之憑證，免納印花稅", "領受賑金、恤金、養老金收據，應按銀錢收據稅率計貼", "小規模營業人所開立有品名數量及價格等事項，具營業發票性質的收據， 非屬印花稅課稅範圍", "各級政府機關及鄉（鎮、市、區）公所所立或使用在一般應負納稅義務之 各種憑證，免納印花稅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:28+00:00", "source_pdf_sha1": "340fd4aa51e1", "answer_pdf_sha1": "2b16893eca27", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "305", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00227', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-113-d3ff7f6b', 'sub-disabled-6f0ba476-07', NULL, 'essay', '假設獨占廠商面對的反需求曲線及總成本函數分別為P400.6Q、
TC 48Q0.2Q2。請回答下列問題，並詳列計算過程：
利潤最大化產量及利潤水準。（6 分）
若政府對獨占廠商課徵10 元的定額稅（lump-sumtax），請計算此
獨占廠商利潤最大化產量和利潤水準。（7 分）
若政府對獨占廠商課徵每單位10 元的從量稅（specifictax），請計
算此獨占廠商利潤最大化產量。（6 分）
若政府對獨占廠商課徵10%的從價稅（advaloremtax），請計算此
獨占廠商利潤最大化產量。（6分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:28+00:00", "source_pdf_sha1": "6f76ab1b056f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "305", "s": "0902", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00228', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-113-d3ff7f6b', 'sub-disabled-6f0ba476-07', NULL, 'essay', '假設某一開放經濟體各部門支出如下：
消費函數為C 580.4Yd，可支配所得Yd Y T，稅收淨額T 30
億元，投資支出I 15億元，政府支出G 20億元，淨出口函數為
NX 150.2Y，其中，Y 是所得。請回答下列問題，並詳列計算過程：
均衡國內生產毛額（GDP）。（4 分）
總支出線的斜率。（3分）
淨出口乘數及稅收淨額乘數。（6 分）
若充分就業的均衡所得為 140億元，則此時會有膨脹或緊縮缺口？
缺口有多大？（6 分）
若以政府支出做為消除此缺口的手段，則政府支出須變動多少，才
能達到充分就業水準？在政府支出水準下，政府預算會發生多少赤
字（或盈餘）？（6 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:28+00:00", "source_pdf_sha1": "6f76ab1b056f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "305", "s": "0902", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00229', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-113-d3ff7f6b', 'sub-disabled-6f0ba476-07', NULL, 'single_choice', '假設所有財貨的生產皆是固定規模報酬，有關機會成本與國際貿易型態， 下列敘述何者正確？', '["具有絕對利益意味同時擁有比較利益", "假設國家 A 相對於國家 B 在生產電腦時可以用更少的投入得到相同的 產出，則國家A具有生產電腦的比較利益", "假設國家 A 和 B 在生產所有財貨皆有相同的機會成本，則兩國進行國 際貿易不會帶來專業化利得", "假設國家A在生產所有財貨皆較有效率，則兩國進行國際貿易不會互蒙 其利"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:28+00:00", "source_pdf_sha1": "6f76ab1b056f", "answer_pdf_sha1": "aff3e98fba69", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "305", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00230', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-113-d3ff7f6b', 'sub-disabled-6f0ba476-07', NULL, 'single_choice', '某財貨的市場需求函數為Q=4-P，其中Q為需求量，P為價格。當價格為 2元時，價格的需求彈性為何？', '["-1/4", "-1", "-2", "-4"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:28+00:00", "source_pdf_sha1": "6f76ab1b056f", "answer_pdf_sha1": "aff3e98fba69", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "305", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL)
